 229→const extractFromLexical = (contentJson) => {
 230→    try {
 231→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
 232→        const texts = [];
 233→        let firstImage = null;
 234→
 235→        const walk = (node) => {
 236→            if (!node || typeof node !== 'object') return;
 237→
 238→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
 239→            if (nodeType === 'text' && typeof node.text === 'string') {
 240→                texts.push(node.text);
 241→            }
 242→
 243→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
 244→            if (!firstImage && isImageNode) {
 245→                const image = imageFromNodeLike(node);
 246→                if (image) {
 247→                    firstImage = image;
 248→                }
 249→            }
 250→
 251→            if (Array.isArray(node.children)) {
 252→                node.children.forEach(walk);
 253→            }
 254→        };
 255→
 256→        if (parsed?.root) {
 257→            walk(parsed.root);
 258→        }
 259→
 260→        return {
 261→            text: normalizeWhitespace(texts.join(' ')),
 262→            image: firstImage
 263→        };
 264→    } catch {
 265→        return { text: '', image: null };
 266→    }
 267→};
