 383→const isSafeRemoteImageUrl = (imageUrl) => {
 384→    try {
 385→        const parsed = new URL(imageUrl);
 386→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 387→            return false;
 388→        }
 389→
 390→        const hostname = parsed.hostname.toLowerCase();
 391→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
 392→            return false;
 393→        }
 394→
 395→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
 396→            return false;
 397→        }
 398→
 399→        return true;
 400→    } catch {
 401→        return false;
 402→    }
 403→};
