1391→        supabase
1392→            .from('users')
1393→            .select(selectColumns)
1394→            .ilike('username', `%${escapedQuery}%`)
1395→            .limit(parsedLimit + 1)
1396→    ]);
1397→
1398→    if(nameResult.error || usernameResult.error){
1399→        console.error('user search error:', nameResult.error?.message || usernameResult.error?.message);
1400→        throw {status: 500, error: 'supabase error while searching users'};
