 45→// ══════════════════════════════════════════════════════════════════════
 46→// Step 1: Recompute all galaxy centroids
 47→// ══════════════════════════════════════════════════════════════════════
 48→export async function recomputeAllCentroids() {
 49→    // Get all users who have public posts with embeddings
 50→    const { data: users, error: usersErr } = await supabase
 51→        .from('journals')
 52→        .select('user_id')
 53→        .eq('privacy', 'public')
 54→        .not('embeddings', 'is', null);
 55→
 56→    if (usersErr) throw new Error(`Failed to query users: ${usersErr.message}`);
 57→
 58→    const uniqueUserIds = [...new Set((users || []).map(u => u.user_id))];
 59→    console.log(`[galaxy-settle] Found ${uniqueUserIds.length} users with embeddings`);
 60→
 61→    let upserted = 0;
 62→    for (const userId of uniqueUserIds) {
 63→        // Compute mean embedding via RPC or manual fetch
 64→        const { data: posts, error: postsErr } = await supabase
 65→            .from('journals')
 66→            .select('embeddings')
 67→            .eq('user_id', userId)
 68→            .eq('privacy', 'public')
 69→            .not('embeddings', 'is', null);
 70→
 71→        if (postsErr || !posts || posts.length === 0) continue;
 72→
 73→        // Compute mean embedding
 74→        const dim = 384;
 75→        const mean = new Array(dim).fill(0);
 76→        for (const post of posts) {
 77→            const emb = post.embeddings;
 78→            if (!emb || emb.length !== dim) continue;
 79→            for (let i = 0; i < dim; i++) mean[i] += emb[i];
 80→        }
 81→        for (let i = 0; i < dim; i++) mean[i] /= posts.length;
 82→
 83→        // Normalize the mean embedding
 84→        let norm = 0;
 85→        for (let i = 0; i < dim; i++) norm += mean[i] * mean[i];
 86→        norm = Math.sqrt(norm);
 87→        if (norm > 0) {
 88→            for (let i = 0; i < dim; i++) mean[i] /= norm;
 89→        }
 90→
 91→        // Format as pgvector string
 92→        const vectorStr = `[${mean.join(',')}]`;
 93→
 94→        const { error: upsertErr } = await supabase
 95→            .from('galaxy_centroids')
 96→            .upsert({
 97→                user_id: userId,
 98→                mean_embedding: vectorStr,
 99→                post_count: posts.length,
100→                updated_at: new Date().toISOString()
101→            }, { onConflict: 'user_id' });
102→
103→        if (upsertErr) {
104→            console.error(`[galaxy-settle] Failed to upsert centroid for ${userId}:`, upsertErr.message);
105→        } else {
106→            upserted++;
107→        }
108→    }
109→
110→    console.log(`[galaxy-settle] Upserted ${upserted} centroids`);
111→    return upserted;
112→}
113→
114→// ══════════════════════════════════════════════════════════════════════
115→// Step 2: Recompute galaxy edges (similarity between centroids)
116→// ══════════════════════════════════════════════════════════════════════
117→export async function recomputeGalaxyEdges() {
118→    const { data: centroids, error } = await supabase
119→        .from('galaxy_centroids')
120→        .select('user_id, mean_embedding')
121→        .not('mean_embedding', 'is', null);
122→
123→    if (error) throw new Error(`Failed to fetch centroids: ${error.message}`);
124→    if (!centroids || centroids.length < 2) {
125→        console.log('[galaxy-settle] Not enough centroids for edges');
126→        return 0;
127→    }
128→
129→    const THRESHOLD = 0.25;
130→    const edges = [];
131→
132→    for (let i = 0; i < centroids.length; i++) {
133→        for (let j = i + 1; j < centroids.length; j++) {
134→            const a = centroids[i];
135→            const b = centroids[j];
136→
137→            // Parse embeddings (they come as arrays from Supabase)
138→            const embA = Array.isArray(a.mean_embedding) ? a.mean_embedding : null;
139→            const embB = Array.isArray(b.mean_embedding) ? b.mean_embedding : null;
140→            if (!embA || !embB) continue;
141→
142→            const similarity = dot(embA, embB);
143→            if (similarity >= THRESHOLD) {
144→                // Ensure user_a < user_b
145→                const [userA, userB] = a.user_id < b.user_id
146→                    ? [a.user_id, b.user_id]
147→                    : [b.user_id, a.user_id];
148→                edges.push({ user_a: userA, user_b: userB, similarity });
149→            }
150→        }
151→    }
152→
153→    // Clear old edges and insert new ones
154→    await supabase.from('galaxy_edges').delete().neq('similarity', -999);
155→
156→    if (edges.length > 0) {
157→        // Batch insert in chunks of 500
158→        for (let i = 0; i < edges.length; i += 500) {
159→            const chunk = edges.slice(i, i + 500);
160→            const { error: insertErr } = await supabase
161→                .from('galaxy_edges')
162→                .upsert(chunk, { onConflict: 'user_a,user_b' });
163→            if (insertErr) {
164→                console.error('[galaxy-settle] Edge insert error:', insertErr.message);
165→            }
166→        }
167→    }
168→
169→    console.log(`[galaxy-settle] Computed ${edges.length} galaxy edges`);
170→    return edges.length;
171→}
