  3→// ── Hash helpers (mirror client-side userHomeCoords) ──────────────────
  4→const simpleHash = (str) => {
  5→    let h = 0;
  6→    for (let i = 0; i < str.length; i++) {
  7→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
  8→    }
  9→    return Math.abs(h);
 10→};
 11→
 12→const userHomeCoords = (userId) => {
 13→    const mid = Math.floor(userId.length / 2);
 14→    const xHash = simpleHash(userId.slice(0, mid));
 15→    const yHash = simpleHash(userId.slice(mid));
 16→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
 17→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
 18→    return { x, y };
 19→};
 20→
 21→const spiralLayout = (index) => {
 22→    if (index === 0) return { dx: 0, dy: 0 };
 23→    const angle = index * 0.8;
 24→    const radius = 30 * Math.sqrt(index);
 25→    return { dx: radius * Math.cos(angle), dy: radius * Math.sin(angle) };
 26→};
