173→// ══════════════════════════════════════════════════════════════════════
174→// Step 3: Force-directed galaxy position settle
175→// ══════════════════════════════════════════════════════════════════════
176→export async function settleGalaxyPositions() {
177→    const { data: centroids, error: centErr } = await supabase
178→        .from('galaxy_centroids')
179→        .select('user_id, post_count');
180→
181→    if (centErr) throw new Error(`Failed to fetch centroids: ${centErr.message}`);
182→    if (!centroids || centroids.length === 0) return;
183→
184→    const { data: edges, error: edgeErr } = await supabase
185→        .from('galaxy_edges')
186→        .select('user_a, user_b, similarity');
187→
188→    if (edgeErr) throw new Error(`Failed to fetch edges: ${edgeErr.message}`);
189→
190→    // Initialize positions from hash-based coords
191→    const nodes = new Map();
192→    for (const c of centroids) {
193→        const home = userHomeCoords(c.user_id);
194→        nodes.set(c.user_id, {
195→            x: home.x,
196→            y: home.y,
197→            vx: 0,
198→            vy: 0,
199→            count: c.post_count || 1,
200→        });
201→    }
202→
203→    const nodeIds = Array.from(nodes.keys());
204→    let temperature = INITIAL_TEMP;
205→
206→    for (let iter = 0; iter < MAX_ITERATIONS; iter++) {
207→        // Reset forces
208→        const forces = new Map();
209→        for (const id of nodeIds) forces.set(id, { fx: 0, fy: 0 });
210→
211→        // Repulsion: all pairs
212→        for (let i = 0; i < nodeIds.length; i++) {
213→            for (let j = i + 1; j < nodeIds.length; j++) {
214→                const a = nodes.get(nodeIds[i]);
215→                const b = nodes.get(nodeIds[j]);
216→                const dx = b.x - a.x;
217→                const dy = b.y - a.y;
218→                const distSq = dx * dx + dy * dy;
219→                const dist = Math.sqrt(distSq) || 1;
220→
221→                const force = REPULSION_K * (a.count + b.count) / distSq;
222→                const fx = (dx / dist) * force;
223→                const fy = (dy / dist) * force;
224→
225→                const fa = forces.get(nodeIds[i]);
226→                const fb = forces.get(nodeIds[j]);
227→                fa.fx -= fx;
228→                fa.fy -= fy;
229→                fb.fx += fx;
230→                fb.fy += fy;
231→            }
232→        }
233→
234→        // Attraction: edge pairs (spring force)
235→        if (edges) {
236→            for (const edge of edges) {
237→                const a = nodes.get(edge.user_a);
238→                const b = nodes.get(edge.user_b);
239→                if (!a || !b) continue;
240→
241→                const dx = b.x - a.x;
242→                const dy = b.y - a.y;
243→                const dist = Math.sqrt(dx * dx + dy * dy) || 1;
244→                const idealDist = 2000 * (1 - edge.similarity);
245→                const force = ATTRACTION_K * edge.similarity * (dist - idealDist);
246→                const fx = (dx / dist) * force;
247→                const fy = (dy / dist) * force;
248→
249→                const fa = forces.get(edge.user_a);
250→                const fb = forces.get(edge.user_b);
251→                fa.fx += fx;
252→                fa.fy += fy;
253→                fb.fx -= fx;
254→                fb.fy -= fy;
255→            }
256→        }
257→
258→        // Apply forces with cooling and damping
259→        let maxDisp = 0;
260→        for (const id of nodeIds) {
261→            const node = nodes.get(id);
262→            const f = forces.get(id);
263→
264→            node.vx = (node.vx + f.fx) * DAMPING;
265→            node.vy = (node.vy + f.fy) * DAMPING;
266→
267→            const dispX = node.vx * temperature;
268→            const dispY = node.vy * temperature;
269→
270→            node.x += dispX;
271→            node.y += dispY;
272→
273→            // Soft boundary
274→            if (node.x > BOUNDARY) node.x = BOUNDARY - (node.x - BOUNDARY) * 0.5;
275→            if (node.x < -BOUNDARY) node.x = -BOUNDARY - (node.x + BOUNDARY) * 0.5;
276→            if (node.y > BOUNDARY) node.y = BOUNDARY - (node.y - BOUNDARY) * 0.5;
277→            if (node.y < -BOUNDARY) node.y = -BOUNDARY - (node.y + BOUNDARY) * 0.5;
278→
279→            const disp = Math.sqrt(dispX * dispX + dispY * dispY);
280→            if (disp > maxDisp) maxDisp = disp;
281→        }
282→
283→        temperature *= COOLING;
284→
285→        if (maxDisp < 1.0) {
286→            console.log(`[galaxy-settle] Converged at iteration ${iter}`);
287→            break;
288→        }
289→    }
290→
291→    // Write settled positions to galaxy_centroids
292→    for (const id of nodeIds) {
293→        const node = nodes.get(id);
294→        const { error: updateErr } = await supabase
295→            .from('galaxy_centroids')
296→            .update({
297→                galaxy_x: Math.round(node.x * 100) / 100,
298→                galaxy_y: Math.round(node.y * 100) / 100,
299→                updated_at: new Date().toISOString()
300→            })
301→            .eq('user_id', id);
302→
303→        if (updateErr) {
304→            console.error(`[galaxy-settle] Failed to update position for ${id}:`, updateErr.message);
305→        }
306→    }
307→
308→    console.log(`[galaxy-settle] Settled ${nodeIds.length} galaxy positions`);
309→}
