587→export async function runFullSettle() {
588→    console.log('[galaxy-settle] Starting full settle...');
589→    const start = Date.now();
590→
591→    await recomputeAllCentroids();
592→    await recomputeGalaxyEdges();
593→    await settleGalaxyPositions();
594→    await settleStarPositions();
595→
